changeSet.sql:
-- Art.21.2(b) — Incident Handling: alerts linked to incidents are evidence INSERT INTO hive_compliance_control_mapping (control_id, mapping_type, data_types, cel_condition, description, weight, evidence_retention_days) SELECT c.id, 'EVIDENCE', 'ALERT', 'logx.dataType == "ALERT" && logx.incident_id != null && logx.incident_id != ""', 'Security alert linked to an incident ID — confirms that incident handling process is active per NIS2 Art.21.2(b)', 1.0, 90 FROM hive_compliance_control_config c JOIN hive_compliance_standard_section sec ON c.standard_section_id = sec.id JOIN hive_compliance_standard std ON sec.standard_id = std.id WHERE std.standard_name = 'NIS2' AND c.control_name LIKE '%Art.21.2(b)%';
-- Art.21.2(b) — NIS2 72-hour notification window: high-severity incident with no notes after 72h = VIOLATION -- Handled as a time-bounded INDICATOR in the event processor; here we record the intent INSERT INTO hive_compliance_control_mapping (control_id, mapping_type, data_types, cel_condition, description, weight, evidence_retention_days) SELECT c.id, 'INDICATOR', 'INCIDENT', 'logx.dataType == "INCIDENT" && logx.incident_status == "OPEN" && logx.incident_severity in ["HIGH","CRITICAL"]', 'Open high/critical incident — monitor for NIS2 Art.21.2(b) 72-hour notification SLA compliance', 0.8, 30 FROM hive_compliance_control_config c JOIN hive_compliance_standard_section sec ON c.standard_section_id = sec.id JOIN hive_compliance_standard std ON sec.standard_id = std.id WHERE std.standard_name = 'NIS2' AND c.control_name LIKE '%Art.21.2(b)%';
-- Art.21.2(i) — Access control: Windows login audit trail (4624/4625/4634) = EVIDENCE INSERT INTO hive_compliance_control_mapping (control_id, mapping_type, data_types, cel_condition, description, weight, evidence_retention_days) SELECT c.id, 'EVIDENCE', 'WINDOWS_AGENT', 'logx.dataType == "WINDOWS_AGENT" && logx.winlog.event_id in [4624, 4625, 4634]', 'Windows logon/logoff events (4624, 4625, 4634) confirm access control audit logging per NIS2 Art.21.2(i)', 1.0, 90 FROM hive_compliance_control_config c JOIN hive_compliance_standard_section sec ON c.standard_section_id = sec.id JOIN hive_compliance_standard std ON sec.standard_id = std.id WHERE std.standard_name = 'NIS2' AND c.control_name LIKE '%Art.21.2(i)%';
-- Art.21.2(i) — Deprovisioning: account deleted events = EVIDENCE INSERT INTO hive_compliance_control_mapping (control_id, mapping_type, data_types, cel_condition, description, weight, evidence_retention_days) SELECT c.id, 'EVIDENCE', 'WINDOWS_AGENT', 'logx.dataType == "WINDOWS_AGENT" && logx.winlog.event_id in [4720, 4726]', 'Account creation (4720) and deletion (4726) events satisfy NIS2 Art.21.2(i) identity lifecycle requirements', 1.0, 90 FROM hive_compliance_control_config c JOIN hive_compliance_standard_section sec ON c.standard_section_id = sec.id JOIN hive_compliance_standard std ON sec.standard_id = std.id WHERE std.standard_name = 'NIS2' AND c.control_name LIKE '%Art.21.2(i)%';
-- Art.21.2(j) — MFA: Windows events with MFA keywords in logon data = EVIDENCE INSERT INTO hive_compliance_control_mapping (control_id, mapping_type, data_types, cel_condition, description, weight, evidence_retention_days) SELECT c.id, 'EVIDENCE', 'WINDOWS_AGENT', 'logx.dataType == "WINDOWS_AGENT" && logx.winlog.event_id == 4624 && (logx.winlog.event_data.AuthenticationPackageName matches ".*(MFA|OATH|Authenticator|DUO|FIDO|Smartcard).*")', 'Successful logon with MFA authentication package confirms multi-factor authentication is active per NIS2 Art.21.2(j)', 1.0, 90 FROM hive_compliance_control_config c JOIN hive_compliance_standard_section sec ON c.standard_section_id = sec.id JOIN hive_compliance_standard std ON sec.standard_id = std.id WHERE std.standard_name = 'NIS2' AND c.control_name LIKE '%Art.21.2(j)%';
-- Art.21.2(j) — MFA bypass/failure = VIOLATION INSERT INTO hive_compliance_control_mapping (control_id, mapping_type, data_types, cel_condition, description, weight, evidence_retention_days) SELECT c.id, 'VIOLATION', 'WINDOWS_AGENT', 'logx.dataType == "WINDOWS_AGENT" && logx.winlog.event_id == 4625 && logx.winlog.event_data.LogonType in ["10", "3"]', 'Remote or network logon failure (4625 type 3/10) may indicate MFA bypass attempt, violating NIS2 Art.21.2(j)', 1.0, 180 FROM hive_compliance_control_config c JOIN hive_compliance_standard_section sec ON c.standard_section_id = sec.id JOIN hive_compliance_standard std ON sec.standard_id = std.id WHERE std.standard_name = 'NIS2' AND c.control_name LIKE '%Art.21.2(j)%';
-- Art.21.2(f) — Effectiveness: UBA anomalies firing = EVIDENCE that monitoring is working INSERT INTO hive_compliance_control_mapping (control_id, mapping_type, data_types, cel_condition, description, weight, evidence_retention_days) SELECT c.id, 'EVIDENCE', 'UBA', 'logx.dataType == "UBA" && logx.anomaly_score > 0', 'UBA anomaly fired — confirms automated risk-measure effectiveness monitoring per NIS2 Art.21.2(f)', 0.9, 90 FROM hive_compliance_control_config c JOIN hive_compliance_standard_section sec ON c.standard_section_id = sec.id JOIN hive_compliance_standard std ON sec.standard_id = std.id WHERE std.standard_name = 'NIS2' AND c.control_name LIKE '%Art.21.2(f)%';
-- Art.21.2(h) — Crypto: TLS/SSL error events = INDICATOR of unencrypted traffic INSERT INTO hive_compliance_control_mapping (control_id, mapping_type, data_types, cel_condition, description, weight, evidence_retention_days) SELECT c.id, 'INDICATOR', 'GENERIC', 'logx.dataType == "GENERIC" && (logx.message matches ".*(SSL|TLS).*(error|failure|handshake|cert).*" || logx.message matches ".*certificate.*expired.*")', 'TLS/SSL error or expired certificate detected — indicator of potential unencrypted traffic violating NIS2 Art.21.2(h) encryption policy', 0.8, 90 FROM hive_compliance_control_config c JOIN hive_compliance_standard_section sec ON c.standard_section_id = sec.id JOIN hive_compliance_standard std ON sec.standard_id = std.id WHERE std.standard_name = 'NIS2' AND c.control_name LIKE '%Art.21.2(h)%';
-- Art.21.2(b) — Audit log cleared = VIOLATION (hinders incident investigation) INSERT INTO hive_compliance_control_mapping (control_id, mapping_type, data_types, cel_condition, description, weight, evidence_retention_days) SELECT c.id, 'VIOLATION', 'WINDOWS_AGENT', 'logx.dataType == "WINDOWS_AGENT" && (logx.winlog.event_id == 1102 || logx.winlog.event_id == 1100)', 'Audit log cleared (1102) or logging service stopped (1100) hampers incident handling — violates NIS2 Art.21.2(b)', 1.0, 365 FROM hive_compliance_control_config c JOIN hive_compliance_standard_section sec ON c.standard_section_id = sec.id JOIN hive_compliance_standard std ON sec.standard_id = std.id WHERE std.standard_name = 'NIS2' AND c.control_name LIKE '%Art.21.2(b)%';
